}

/**
 * List problems with optional filters and includeComponents flag.
 * When includeComponents=true, metadata.componentLanguageTotals and componentStatusTotals
 * are computed from the filtered and limited result set.
 *
 * @param {Object} params - Parameters including filters, limit, includeComponents
 * @param {Function} getProblems - async function to get problems from DB with filters and limit
 * @returns {Promise<Object>} - { problems: [...], metadata: { componentLanguageTotals, componentStatusTotals } }
 */
async function listProblems(params, getProblems) {
  const { filters = {}, limit, includeComponents } = params;

  // Fetch problems with filters and limit applied
  const problems = await getProblems(filters, limit);

  const metadata = {};

  if (includeComponents) {
    // Compute componentLanguageTotals and componentStatusTotals from filtered and limited problems
    const componentLanguageTotals = {};
    const componentStatusTotals = {};

    for (const problem of problems) {
      if (problem.components && Array.isArray(problem.components)) {
        for (const comp of problem.components) {
          if (comp.language) {
            componentLanguageTotals[comp.language] = (componentLanguageTotals[comp.language] || 0) + 1;
          }
          if (comp.status) {
            componentStatusTotals[comp.status] = (componentStatusTotals[comp.status] || 0) + 1;
          }
        }
      }
    }

    metadata.componentLanguageTotals = componentLanguageTotals;
    metadata.componentStatusTotals = componentStatusTotals;
  }

  return { problems, metadata };
}

module.exports = {
  solve,
  listProblems,
};
